category/java/bestpractices.xml/UnusedAs.checker_dsl:
EXISTS (`AssignmentEntry AE`) {
  AND {
    (`AE is flagged as an unused assignment by the dataflow analysis`),
    NOT {
      AND {
        (`AE is a unary reassignment`),
        (`AE's location is an ASTUnaryExpression UE`),
        (`UE's operator is a prefix operator`),
        (`UE's operator is not a pure operator`),
        (`the rule property CHECK_PREFIX_INCREMENT is false`),
        (`UE's parent is not an ASTExpressionStatement`)
      }
    },
    OR {
      AND {
        (`the set of killer assignments for AE is empty`),
        NOT { (`AE is a field assignment`) },
        NOT {
          AND {
            (`the rule property REPORT_UNUSED_VARS is false`),
            OR {
              (`AE is an initializer assignment`),
              (`AE is a blank declaration assignment`)
            }
          }
        }
      },
      EXISTS (`AssignmentEntry K1`) {
        AND {
          (`K1 is the single killer assignment for AE`),
          OR {
            AND {
              (`K1's location is the same as AE's location`),
              NOT {
                AND {
                  (`the rule property REPORT_UNUSED_VARS is false`),
                  OR {
                    (`AE is an initializer assignment`),
                    (`AE is a blank declaration assignment`)
                  }
                }
              },
              NOT { (`AE is a foreach loop variable assignment`) }
            },
            (`K1's location is different from AE's location`)
          }
        }
      },
      EXISTS (`AssignmentEntry K2`, `AssignmentEntry K3`) {
        AND {
          (`K2 is a killer assignment for AE`),
          (`K3 is a killer assignment for AE`),
          (`K2 is different from K3`)
        }
      }
    },
    NOT {
      AND {
        (`the reason string for AE's violation is null`),
        OR {
          (`the name of AE's variable starts with "ignored"`),
          (`the name of AE's variable starts with "unused"`),
          (`the name of AE's variable is exactly "_"`)
        }
      }
    }
  }
}

category/java/multithreading.xml/DoubleC.checker_dsl:
EXISTS (`method declaration MD`) {
