    EXISTS (`return statement RS`) {
      AND {
        (`RS is a descendant of MD`),
        (`RS is the only return statement descendant of MD`),
        EXISTS (`named reference expression NRE`) {
          AND {
            (`NRE is the expression of RS`),
            (`NRE references a variable symbol VS`),
            NOT {
              OR {
                (`VS is a field symbol with the volatile modifier`),
                EXISTS (`local variable symbol LVS`) {
                  AND {
                    (`LVS is the same as VS`),
                    (`LVS has a corresponding ASTVariableId node VID`),
                    OR {
                      (`VID has no initializer expression`),
                      EXISTS (`expression INIT`) {
                        AND {
                          (`INIT is the initializer of VID`),
                          EXISTS (`named reference expression NRE_INIT`) {
                            AND {
                              (`NRE_INIT is the same as INIT`),
                              (`NRE_INIT references a field symbol FS_INIT`),
                              (`FS_INIT has the volatile modifier`)
                            }
                          }
                        }
                      }
                    },
                    FORALL (`assignment expression AE_LOCAL`) {
                      AND {
                        (`AE_LOCAL is a descendant of MD`),
                        (`the left operand of AE_LOCAL is a reference to LVS`),
                        EXISTS (`expression RIGHT_LOCAL`) {
                          AND {
                            (`RIGHT_LOCAL is the right operand of AE_LOCAL`),
                            EXISTS (`named reference expression NRE_RIGHT`) {
                              AND {
                                (`NRE_RIGHT is the same as RIGHT_LOCAL`),
                                (`NRE_RIGHT references a field symbol FS_RIGHT`),
                                (`FS_RIGHT has the volatile modifier`)
                              }
                            }
                          }
                        }
                      }
                    }
                  }
                }
              }
            },
            EXISTS (`if statement OUTER_IF`) {
              AND {
                (`OUTER_IF is a descendant of MD`),
                (`OUTER_IF has at least one descendant if statement`),
                (`OUTER_IF has no ancestor if statement`),
                EXISTS (`infix expression COND_OUTER`) {
                  AND {
                    (`COND_OUTER is the condition of OUTER_IF`),
                    (`COND_OUTER uses the equality operator ==`),
                    EXISTS (`null literal NL_OUTER`) {
                      AND {
                        (`NL_OUTER is a child of COND_OUTER`),
                        (`the other operand of COND_OUTER relative to NL_OUTER is a reference to VS`)
                      }
                    }
                  }
                },
                EXISTS (`synchronized statement SYNC`) {
                  AND {
                    (`SYNC is a descendant of OUTER_IF`),
                    (`SYNC is the only synchronized statement descendant of OUTER_IF`),
                    (`SYNC has OUTER_IF as an ancestor`)
                  }
                },
                EXISTS (`assignment expression AE_PATTERN`) {
                  AND {
                    (`AE_PATTERN is a descendant of OUTER_IF`),
                    EXISTS (`if statement INNER_IF`) {
                      AND {
                        (`INNER_IF is a descendant of OUTER_IF`),
                        (`INNER_IF is an if statement`),
                        EXISTS (`infix expression COND_INNER`) {
                          AND {
                            (`COND_INNER is the condition of INNER_IF`),
                            (`COND_INNER uses the equality operator ==`),
                            EXISTS (`null literal NL_INNER`) {
                              AND {
                                (`NL_INNER is a child of COND_INNER`),
                                (`the other operand of COND_INNER relative to NL_INNER is a reference to VS`)
                              }
                            }
                          }
                        },
                        (`AE_PATTERN is a descendant of INNER_IF`),
                        (`AE_PATTERN is an assignment expression`)
                      }
                    },
                    (`the left operand of AE_PATTERN is a reference to VS`)
                  }
                },
                FORALL (`assignment expression AE_CHECK`) {
                  AND {
                    (`AE_CHECK is a descendant of OUTER_IF`),
                    EXISTS (`if statement INNER_IF_CHECK`) {
                      AND {
                        (`INNER_IF_CHECK is a descendant of OUTER_IF`),
                        (`INNER_IF_CHECK is an if statement`),
                        EXISTS (`infix expression COND_INNER_CHECK`) {
                          AND {
                            (`COND_INNER_CHECK is the condition of INNER_IF_CHECK`),
                            (`COND_INNER_CHECK uses the equality operator ==`),
                            EXISTS (`null literal NL_INNER_CHECK`) {
                              AND {
                                (`NL_INNER_CHECK is a child of COND_INNER_CHECK`),
                                (`the other operand of COND_INNER_CHECK relative to NL_INNER_CHECK is a reference to VS`)
                              }
                            }
                          }
                        },
                        (`AE_CHECK is a descendant of INNER_IF_CHECK`),
                        (`AE_CHECK is an assignment expression`)
                      }
                    },
                    (`the left operand of AE_CHECK is a reference to VS`)
