          (`OP is an instance of ASTLambdaExpression`),
          (`OP is an instance of ASTMethodReference`)
        },
        NOT { (`context is missing`) },
        NOT { (`context has kind INVOCATION`) },
        (`coercionType equals context.getTargetType()`)
      },
      AND {
        NOT { OR {
          (`OP is an instance of ASTLambdaExpression`),
          (`OP is an instance of ASTMethodReference`)
        } },
        OR {
          (`operandType equals coercionType`),
          AND {
            (`context is missing`),
            NOT { (`operandType is the bottom type (null type)`) },
